context.schema:
{
  "description": "Sleek SaaS analytics data warehouse \u2014 3 core tables covering customer, revenue, and churn dimensions",
  "tables": {
    "customers": {
      "description": "Customer master table. One row per customer. Contains customer profile, acquisition, and lifetime value information.",
      "columns": {
        "customer_id": "Unique customer identifier (e.g. SLEEK-0001)",
        "signup_date": "Date customer first signed up (YYYY-MM-DD)",
        "market": "Operating market: SG (Singapore), HK (Hong Kong), AU (Australia), UK (United Kingdom)",
        "segment": "Customer segment based on company size: Startup (2-8 employees), SME (8-40 employees), Corporate (40-150 employees)",
        "plan": "Subscription plan: Starter (basic accounting + compliance), Growth (+ payroll), Full Compliance (all services)",
        "acquisition_channel": "How customer was acquired: Organic (SEO/content), Paid (ads), Referral (existing customer referral), Partner (accounting firm / bank referral)",
        "is_foreign_founder": "Boolean \u2014 whether the company founder is a foreign national, affects incorporation fee",
        "headcount": "Number of employees, used to calculate Payroll MRR",
        "cac": "Customer acquisition cost in USD \u2014 total marketing/sales spend to acquire this customer",
        "churned": "Boolean \u2014 whether customer has churned",
        "churn_date": "Month customer churned in YYYY-MM format, null if still active",
        "ltv": "Cumulative revenue generated by this customer to date in USD"
      }
    },
    "monthly_revenue": {
      "description": "Monthly recurring revenue by customer and product. One row per customer per product per month. Excludes one-time Incorporation fees for MRR analysis.",
      "columns": {
        "customer_id": "Foreign key to customers table",
        "month": "Revenue month in YYYY-MM format",
        "market": "Operating market: SG, HK, AU, UK",
        "segment": "Customer segment: Startup, SME, Corporate",
        "plan": "Subscription plan at time of billing: Starter, Growth, Full Compliance",
        "product": "Product line: Accounting (bookkeeping + reporting), Compliance (corporate secretarial + regulatory), Payroll (payroll processing, Growth and Full Compliance only), Incorporation (one-time company registration fee, appears in first month only)",
        "mrr": "Monthly recurring revenue in USD for this product. For Incorporation, this is the one-time setup fee.",
        "event_type": "Revenue event classification: new (first payment), active (renewal, no change), expansion (plan upgrade), churn (cancelled, MRR=0)"
      }
    },
    "monthly_churn": {
      "description": "One row per churned customer. Captures churn timing, financial impact, and reason. Use this table for churn analysis, cohort analysis, and retention investigations.",
      "columns": {
        "customer_id": "Foreign key to customers table",
        "churn_month": "Month customer churned in YYYY-MM format",
        "market": "Operating market at time of churn: SG, HK, AU, UK",
        "segment": "Customer segment at time of churn: Startup, SME, Corporate",
        "plan": "Subscription plan at time of churn: Starter, Growth, Full Compliance",
        "tenure_months": "Number of months customer was active before churning. Higher tenure = more loyal customer lost.",
        "mrr_lost": "Average monthly MRR lost due to this churn in USD",
        "churn_reason_category": "Categorized churn reason: Price (too expensive), Product (missing features / bugs), Competition (switched to competitor), Unknown (no reason given)"
      }
    }
  },
  "relationships": {
    "customers \u2192 monthly_revenue": "customers.customer_id = monthly_revenue.customer_id (one-to-many)",
    "customers \u2192 monthly_churn": "customers.customer_id = monthly_churn.customer_id (one-to-one for churned customers)"
  },
  "key_metrics_guide": {
    "MRR": "Sum of monthly_revenue.mrr WHERE product != 'Incorporation' AND event_type != 'churn'",
    "Churn Rate": "COUNT(monthly_churn) / COUNT(active customers at start of period)",
    "LTV": "customers.ltv (pre-calculated cumulative revenue)",
    "CAC": "customers.cac (pre-calculated acquisition cost)",
    "LTV:CAC": "customers.ltv / customers.cac \u2014 healthy if > 3x",
    "Expansion MRR": "Sum of monthly_revenue.mrr WHERE event_type = 'expansion'"
  }
}
